import Foundation

struct Stock: Identifiable, Codable {
    let id = UUID()
    let ticker: String
    let name: String
    var currentPrice: Double
    var priceChange: Double
    var priceChangePercent: Double
    var volume: Int

    static var mock: Stock {
        Stock(ticker: "AAPL", name: "Apple Inc.", currentPrice: 175.00, priceChange: 1.50, priceChangePercent: 0.86, volume: 75_000_000)
    }
}

enum TradeType: String, Codable {
    case buy = "Buy"
    case sell = "Sell"
}

struct Trade: Identifiable, Codable {
    let id = UUID()
    let stockTicker: String
    let type: TradeType
    let quantity: Int
    let price: Double
    let timestamp: Date

    static var mock: Trade {
        Trade(stockTicker: "AAPL", type: .buy, quantity: 10, price: 170.00, timestamp: Date().addingTimeInterval(-3600))
    }
}

struct PortfolioHolding: Identifiable, Codable {
    let id = UUID()
    let stockTicker: String
    var quantity: Int
    var averagePrice: Double
    var currentPrice: Double? // For display, updated dynamically

    var marketValue: Double {
        guard let currentPrice = currentPrice else { return 0.0 }
        return Double(quantity) * currentPrice
    }

    var totalCost: Double {
        return Double(quantity) * averagePrice
    }

    var profitLoss: Double {
        marketValue - totalCost
    }

    var profitLossPercent: Double {
        guard totalCost > 0 else { return 0.0 }
        return (profitLoss / totalCost) * 100
    }
}

struct UserAccount: Codable {
    var balance: Double
    var tradeHistory: [Trade]
}

struct TradeRequest: Codable {
    let ticker: String
    let type: TradeType
    let quantity: Int
    let price: Double
}

struct TradeResponse: Codable {
    let success: Bool
    let message: String
    let executedTrade: Trade?
}

