        return components?.url
    }

    private func request<T: Decodable>(url: URL, method: String = "GET", body: Data? = nil) -> AnyPublisher<T, APIError> {
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        request.addValue("Bearer \(apiKey)", forHTTPHeaderField: "Authorization") // Example Auth header
        request.httpBody = body

        return URLSession.shared.dataTaskPublisher(for: request)
            .tryMap { data, response in
                guard let httpResponse = response as? HTTPURLResponse else {
                    throw APIError.unknown
                }
                guard (200...299).contains(httpResponse.statusCode) else {
                    let errorString = String(data: data, encoding: .utf8) ?? "Unknown API Error"
                    throw APIError.apiError(errorString)
                }
                return data
            }
            .decode(type: T.self, decoder: JSONDecoder())
            .mapError { error in
                if let apiError = error as? APIError {
                    return apiError
                } else if error is DecodingError {
                    return APIError.decodingError(error)
                } else {
