// MARK: - TradingService.swift

import Foundation
import Combine

class TradingService: ObservableObject {
    @Published var userAccount: UserAccount {
        didSet { saveAccountData() }
    }
    @Published var portfolioHoldings: [PortfolioHolding] {
        didSet { savePortfolioData() }
    }
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?

    private var cancellables = Set<AnyCancellable>()

    init() {
        self.userAccount = UserAccount(balance: 100_000.00, tradeHistory: [])
        self.portfolioHoldings = []
        loadAccountData()
        loadPortfolioData()
    }

    // MARK: - Persistence

    private func saveAccountData() {
        if let encoded = try? JSONEncoder().encode(userAccount) {
            UserDefaults.standard.set(encoded, forKey: "userAccount")
        }
    }

    private func loadAccountData() {
        if let savedAccount = UserDefaults.standard.data(forKey: "userAccount"),
           let decodedAccount = try? JSONDecoder().decode(UserAccount.self, from: savedAccount) {
            self.userAccount = decodedAccount
        }
    }

    private func savePortfolioData() {
        if let encoded = try? JSONEncoder().encode(portfolioHoldings) {
            UserDefaults.standard.set(encoded, forKey: "portfolioHoldings")
        }
    }

    private func loadPortfolioData() {
        if let savedHoldings = UserDefaults.standard.data(forKey: "portfolioHoldings"),
           let decodedHoldings = try? JSONDecoder().decode([PortfolioHolding].self, from: savedHoldings) {
            self.portfolioHoldings = decodedHoldings
        }
    }

    // MARK: - Trading Logic

    func executeTrade(ticker: String, type: TradeType, quantity: Int, currentPrice: Double) {
        isLoading = true
        errorMessage = nil

        let tradeRequest = TradeRequest(ticker: ticker, type: type, quantity: quantity, price: currentPrice)

        APIService.shared.executeTrade(tradeRequest: tradeRequest)
            .receive(on: DispatchQueue.main)
            .sink { [weak self] completion in
                self?.isLoading = false
                if case .failure(let error) = completion {
                    self?.errorMessage = error.localizedDescription
                }
            } receiveValue: { [weak self] response in
                guard let self = self else { return }
                if response.success, let executedTrade = response.executedTrade {
                    self.updatePortfolio(with: executedTrade)
                    self.updateAccountBalance(with: executedTrade)
                    self.userAccount.tradeHistory.insert(executedTrade, at: 0) // Add to history
                    self.errorMessage = nil // Clear any previous error
                } else {
                    self.errorMessage = response.message
                }
            }
            .store(in: &cancellables)
    }

    private func updatePortfolio(with trade: Trade) {
        if let index = portfolioHoldings.firstIndex(where: { $0.stockTicker == trade.stockTicker }) {
            var holding = portfolioHoldings[index]
            if trade.type == .buy {
                let newTotalCost = (holding.totalCost + (Double(trade.quantity) * trade.price))
                let newTotalQuantity = holding.quantity + trade.quantity
                holding.averagePrice = newTotalCost / Double(newTotalQuantity)
                holding.quantity = newTotalQuantity
            } else { // Sell
                holding.quantity -= trade.quantity
            }

            if holding.quantity <= 0 {
                portfolioHoldings.remove(at: index)
            } else {
                portfolioHoldings[index] = holding
            }
        } else if trade.type == .buy {
            let newHolding = PortfolioHolding(stockTicker: trade.stockTicker, quantity: trade.quantity, averagePrice: trade.price)
            portfolioHoldings.append(newHolding)
        }
        // If selling a stock not in portfolio, this shouldn't happen if validation is correct.
    }

    private func updateAccountBalance(with trade: Trade) {
        let tradeValue = Double(trade.quantity) * trade.price
        if trade.type == .buy {
            userAccount.balance -= tradeValue
        } else { // Sell
            userAccount.balance += tradeValue
        }
    }

    func updatePortfolioCurrentPrices(stocks: [Stock]) {
        for stock in stocks {
            if let index = portfolioHoldings.firstIndex(where: { $0.stockTicker == stock.ticker }) {
                portfolioHoldings[index].currentPrice = stock.currentPrice
            }
        }
    }

    func getHolding(for ticker: String) -> PortfolioHolding? {
        portfolioHoldings.first(where: { $0.stockTicker == ticker })
    }

    var totalPortfolioValue: Double {
        portfolioHoldings.reduce(0) { $0 + $1.marketValue }
    }

    var totalProfitLoss: Double {
        portfolioHoldings.reduce(0) { $0 + $1.profitLoss }
    }
}

// MARK: - ViewModels.swift

import Foundation
import Combine
import SwiftUI

class WatchlistViewModel: ObservableObject {
    @Published var stocks: [Stock] = []
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?

    private var cancellables = Set<AnyCancellable>()
    private var timer: AnyCancellable?

    init() {
        fetchWatchlist()
        setupRealtimeUpdates()
    }

    func fetchWatchlist() {
        isLoading = true
        errorMessage = nil
        APIService.shared.fetchWatchlist()
            .receive(on: DispatchQueue.main)
            .sink { [weak self] completion in
                self?.isLoading = false
                if case .failure(let error) = completion {
                    self?.errorMessage = error.localizedDescription
                }
            } receiveValue: { [weak self] stocks in
                self?.stocks = stocks
            }
            .store(in: &cancellables)
    }

    private func setupRealtimeUpdates() {
        timer = Timer.publish(every: 5, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                self?.refreshStockPrices()
            }
    }

    func refreshStockPrices() {
        // Fetch new prices for existing stocks
        stocks.forEach { stock in
            APIService.shared.fetchStockQuote(ticker: stock.ticker)
                .receive(on: DispatchQueue.main)
                .sink { _ in } receiveValue: { [weak self] updatedStock in
                    if let index = self?.stocks.firstIndex(where: { $0.ticker == updatedStock.ticker }) {
                        self?.stocks[index].currentPrice = updatedStock.currentPrice
                        self?.stocks[index].priceChange = updatedStock.priceChange
                        self?.stocks[index].priceChangePercent = updatedStock.priceChangePercent
                        self?.stocks[index].volume = updatedStock.volume
                    }
                }
                .store(in: &cancellables)
        }
    }
}

class StockDetailViewModel: ObservableObject {
    @Published var stock: Stock
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?
    @Published var quantityToTrade: String = "1"

    private var cancellables = Set<AnyCancellable>()
    private var timer: AnyCancellable?

    init(stock: Stock) {
        self.stock = stock
        setupRealtimeUpdates()
    }

    func refreshStockQuote() {
        isLoading = true
        errorMessage = nil
        APIService.shared.fetchStockQuote(ticker: stock.ticker)
            .receive(on: DispatchQueue.main)
            .sink { [weak self] completion in
                self?.isLoading = false
                if case .failure(let error) = completion {
                    self?.errorMessage = error.localizedDescription
                }
            } receiveValue: { [weak self] updatedStock in
                self?.stock = updatedStock
            }
            .store(in: &cancellables)
    }

    private func setupRealtimeUpdates() {
        timer = Timer.publish(every: 3, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                self?.refreshStockQuote()
            }
    }
}

class PortfolioViewModel: ObservableObject {
    @Published var tradingService: TradingService
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?

    private var cancellables = Set<AnyCancellable>()
    private var timer: AnyCancellable?
    
    init(tradingService: TradingService) {
        self.tradingService = tradingService
        setupRealtimeUpdates()
        observeTradingService()
    }

    private func observeTradingService() {
        tradingService.$portfolioHoldings
            .sink { [weak self] _ in
                self?.refreshHoldingPrices() // Refresh prices whenever holdings change
            }
            .store(in: &cancellables)
    }

    func refreshHoldingPrices() {
        isLoading = true
        errorMessage = nil
        let tickers = tradingService.portfolioHoldings.map { $0.stockTicker }
        let fetchPublishers = tickers.map { ticker in
            APIService.shared.fetchStockQuote(ticker: ticker)
                .map { stock -> Stock? in stock }
                .catch { _ in Just(nil) } // Handle errors for individual stocks
                .eraseToAnyPublisher()
        }

        Publishers.MergeMany(fetchPublishers)
            .collect()
            .receive(on: DispatchQueue.main)
            .sink { [weak self] completion in
                self?.isLoading = false
                if case .failure(let error) = completion {
                    self?.errorMessage = error.localizedDescription
                }
            } receiveValue: { [weak self] stocks in
                let validStocks = stocks.compactMap { $0 }
                self?.tradingService.updatePortfolioCurrentPrices(stocks: validStocks)
            }
            .store(in: &cancellables)
    }

    private func setupRealtimeUpdates() {
        timer = Timer.publish(every: 7, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                self?.refreshHoldingPrices()
            }
    }
}


