struct TradeView: View {
    @EnvironmentObject var tradingService: TradingService
    @Binding var isPresented: Bool
    let stock: Stock
    @State private var quantityString: String = "1"
    @State private var tradeType: TradeType = .buy
    @State private var tradeConfirmationMessage: String?
    @State private var showTradeConfirmation = false
    @State private var tradeError: String?

    var quantity: Int {
        Int(quantityString) ?? 0
    }

    var availableFunds: Double {
        tradingService.userAccount.balance
    }

    var estimatedCost: Double {
        Double(quantity) * stock.currentPrice
    }

    var availableSharesToSell: Int {
        tradingService.getHolding(for: stock.ticker)?.quantity ?? 0
    }

    var isTradeValid: Bool {
        guard quantity > 0 else { return false }

        if tradeType == .buy {
            return estimatedCost <= availableFunds
        } else { // Sell
            return quantity <= availableSharesToSell
        }
    }

    var body: some View {
        NavigationView {
            Form {
                Section("Trade Details") {
                    HStack {
                        Text("Stock")
                        Spacer()
                        Text(stock.ticker)
                            .fontWeight(.semibold)
                    }
                    HStack {
                        Text("Current Price")
                        Spacer()
                        Text(stock.currentPrice, format: .currency(code: "USD"))
                    }
                    Picker("Type", selection: $tradeType) {
                        Text("Buy").tag(TradeType.buy)
                        Text("Sell").tag(TradeType.sell)
                    }
                    .pickerStyle(SegmentedPickerStyle())

                    HStack {
                        Text("Quantity")
                        TextField("Quantity", text: $quantityString)
                            .keyboardType(.numberPad)
                            .multilineTextAlignment(.trailing)
                    }
                }

                Section("Summary") {
                    HStack {
                        Text("Estimated Cost / Proceeds")
                        Spacer()
                        Text(estimatedCost, format: .currency(code: "USD"))
                    }
                    HStack {
                        Text("Available Funds")
                        Spacer()
                        Text(availableFunds, format: .currency(code: "USD"))
                    }
                    if tradeType == .sell {
                        HStack {
                            Text("Shares Held")
                            Spacer()
                            Text("\(availableSharesToSell)")
                        }
                    }
                }

                if let error = tradingService.errorMessage {
                    Section {
                        Text(error)
                            .foregroundColor(.red)
                    }
                }

                Section {
                    Button("Confirm \(tradeType.rawValue)") {
                        executeTrade()
                    }
                    .frame(maxWidth: .infinity)
                    .disabled(!isTradeValid || tradingService.isLoading)
                    .listRowBackground(isTradeValid ? (tradeType == .buy ? Color.green : Color.red) : Color.gray)
                    .foregroundColor(.white)
                }
                .alert("Trade \(tradeConfirmationMessage == nil ? "Failed" : "Confirmed")", isPresented: $showTradeConfirmation, actions: {
                    Button("OK") {
                        if tradeError == nil {
                            isPresented = false // Dismiss sheet on successful trade
                        }
                    }
                }, message: {
                    Text(tradeConfirmationMessage ?? tradeError ?? "An unknown error occurred.")
                })
            }
            .navigationTitle("\(tradeType.rawValue) \(stock.ticker)")
            .navigationBarTitleDisplayMode(.inline)
            .toolbar {
                ToolbarItem(placement: .navigationBarLeading) {
                    Button("Cancel") {
                        isPresented = false
                    }
                }
                ToolbarItem(placement: .navigationBarTrailing) {
                    if tradingService.isLoading {
                        ProgressView()
                    }
                }
            }
        }
    }

    private func executeTrade() {
        tradeConfirmationMessage = nil
        tradeError = nil

        tradingService.executeTrade(ticker: stock.ticker, type: tradeType, quantity: quantity, currentPrice: stock.currentPrice)

        // Listen for changes from TradingService for trade outcome
        tradingService.$errorMessage
            .first() // Only interested in the first error/nil after trade attempt
            .sink { [weak self] error in
                if let error = error {
                    self?.tradeError = error
                    self?.showTradeConfirmation = true
                } else {
                    self?.tradeConfirmationMessage = "\(self?.tradeType.rawValue ?? "") \(self?.quantity ?? 0) shares of \(self?.stock.ticker ?? "") at \(self?.stock.currentPrice.formatted(.currency(code: "USD")) ?? "") executed successfully."
                    self?.showTradeConfirmation = true
                }
            }
            .store(in: &tradingService.cancellables) // Use tradingService's cancellables or create a local one.
    }
}

struct PortfolioView: View {
    @EnvironmentObject var tradingService: TradingService
    @StateObject private var viewModel: PortfolioViewModel
    
    init() {
        _viewModel = StateObject(wrappedValue: PortfolioViewModel(tradingService: TradingService.init())) // Initialized with dummy, replaced by env object
    }
    
    var body: some View {
        NavigationView {
            List {
                Section("Account Summary") {
                    HStack {
                        Text("Cash Balance")
                        Spacer()
                        Text(tradingService.userAccount.balance, format: .currency(code: "USD"))
                    }
                    HStack {
                        Text("Total Portfolio Value")
                        Spacer()
                        Text(tradingService.totalPortfolioValue, format: .currency(code: "USD"))
                    }
                    HStack {
                        Text("Total Equity")
                        Spacer()
                        Text(tradingService.userAccount.balance + tradingService.totalPortfolioValue, format: .currency(code: "USD"))
                    }
                    HStack {
                        Text("Total P/L")
                        Spacer()
                        Text(tradingService.totalProfitLoss, format: .currency(code: "USD"))
                            .foregroundColor(tradingService.totalProfitLoss >= 0 ? .green : .red)
                    }
                }

                Section("Holdings") {
                    if viewModel.isLoading {
                        ProgressView("Loading Holdings...")
                    } else if let errorMessage = viewModel.errorMessage {
                        Text("Error: \(errorMessage)")
                            .foregroundColor(.red)
                    } else if tradingService.portfolioHoldings.isEmpty {
                        Text("No holdings yet. Start trading!")
                            .foregroundColor(.gray)
                    } else {
                        ForEach(tradingService.portfolioHoldings) { holding in
                            HoldingRow(holding: holding)
                        }
                    }
                }
            }
            .navigationTitle("Portfolio")
            .toolbar {
                ToolbarItem(placement: .navigationBarTrailing) {
                    Button(action: { viewModel.refreshHoldingPrices() }) {
                        Image(systemName: "arrow.clockwise")
                    }
                }
            }
        }
        .onAppear {
            // Re-assign tradingService from environment object when view appears
            viewModel.tradingService = tradingService
            viewModel.refreshHoldingPrices()
        }
    }
}

struct HoldingRow: View {
    let holding: PortfolioHolding

    var body: some View {
        HStack {
            VStack(alignment: .leading) {
                Text(holding.stockTicker)
                    .font(.headline)
                Text("Qty: \(holding.quantity)")
                    .font(.subheadline)
                    .foregroundColor(.gray)
            }
            Spacer()
            VStack(alignment: .trailing) {
                Text(holding.marketValue, format: .currency(code: "USD"))
                    .font(.headline)
                HStack {
                    Image(systemName: holding.profitLoss >= 0 ? "arrow.up" : "arrow.down")
                        .foregroundColor(holding.profitLoss >= 0 ? .green : .red)
                    Text(holding.profitLoss, format: .number.precision(.fractionLength(2)))
                    Text("(\(holding.profitLossPercent, format: .percent.precision(.fractionLength(2))))")
                }
                .foregroundColor(holding.profitLoss >= 0 ? .green : .red)
                .font(.subheadline)
            }
        }
        .padding(.vertical, 4)
    }
}

struct AccountView: View {
    @EnvironmentObject var tradingService: TradingService

    var body: some View {
        NavigationView {
            List {
                Section("Account Details") {
                    HStack {
                        Text("Cash Balance")
                        Spacer()
                        Text(tradingService.userAccount.balance, format: .currency(code: "USD"))
                    }
                    // Add more account details like name, email etc.
                }

                Section("Trade History") {
                    if tradingService.userAccount.tradeHistory.isEmpty {
                        Text("No trades yet.")
                            .foregroundColor(.gray)
                    } else {
                        ForEach(tradingService.userAccount.tradeHistory) { trade in
                            TradeHistoryRow(trade: trade)
                        }
                    }
                }
            }
            .navigationTitle("Account")
        }
    }
}

struct TradeHistoryRow: View {
    let trade: Trade

    var body: some View {
        HStack {
            VStack(alignment: .leading) {
                Text("\(trade.type.rawValue) \(trade.stockTicker)")
                    .font(.headline)
                Text("\(trade.quantity) @ \(trade.price, format: .currency(code: "USD"))")
                    .font(.subheadline)
                    .foregroundColor(.gray)
            }
            Spacer()
            VStack(alignment: .trailing) {
                Text(trade.timestamp, format: .dateTime.month().day().hour().minute())
                    .font(.subheadline)
                    .foregroundColor(.gray)
                Text((Double(trade.quantity) * trade.price), format: .currency(code: "USD"))
                    .font(.subheadline)
                    .foregroundColor(trade.type == .buy ? .red : .green)
            }
        }
        .padding(.vertical, 4)
    }
}

